import{_ as r,I as e,c as d,o as h,a4 as p,j as a,J as s,a as l,w as c}from"./chunks/framework.BR-X7tCu.js";const F=JSON.parse('{"title":"模型配置高级指南：从资源调度到智能策略","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guides/configuration/model_configuration_guide.md","filePath":"docs/guides/configuration/model_configuration_guide.md","lastUpdated":1782019550000}'),k={name:"docs/guides/configuration/model_configuration_guide.md"};function g(u,i,m,E,_,b){const o=e("VPNolebaseInlineLinkPreview"),n=e("NolebaseGitContributors"),t=e("NolebaseGitChangelog");return h(),d("div",null,[i[2]||(i[2]=p(`<h1 id="模型配置高级指南-从资源调度到智能策略" tabindex="-1">模型配置高级指南：从资源调度到智能策略 <a class="header-anchor" href="#模型配置高级指南-从资源调度到智能策略" aria-label="Permalink to “模型配置高级指南：从资源调度到智能策略”">​</a></h1><p>本文档介绍如何通过 <code>model.toml</code> 配置 Neo-MoFox 的 AI 模型。配置分为三个层次：资源层（API Providers）、能力层（Models）和应用层（Model Tasks）。</p><h2 id="_1-核心概念" tabindex="-1">1. 核心概念 <a class="header-anchor" href="#_1-核心概念" aria-label="Permalink to “1. 核心概念”">​</a></h2><ul><li><strong>资源层 (API Providers)</strong>：定义模型服务提供商，如 DeepSeek、SiliconFlow 或本地部署的 Ollama。</li><li><strong>能力层 (Models)</strong>：定义具体的模型参数，引用资源层的 Provider，并设置价格、特性等。</li><li><strong>应用层 (Model Tasks)</strong>：将定义好的模型分配给 Bot 的具体任务（如聊天、规划、工具调用）。</li></ul><h3 id="_1-2-数据流向可视化" tabindex="-1">1.2 数据流向可视化 <a class="header-anchor" href="#_1-2-数据流向可视化" aria-label="Permalink to “1.2 数据流向可视化”">​</a></h3><p>下面的图清晰地展示了这三层架构之间的依赖关系和数据流向：</p><pre class="mermaid">graph LR
    subgraph 资源层 [API Providers]
        P1[Provider A: SiliconFlow]
        P2[Provider B: Google Gemini]
        P3[Provider C: Local Ollama]
    end

    subgraph 能力层 [Models]
        M1[&quot;name: deepseek-v3.1&lt;br&gt;provider: SiliconFlow&quot;]
        M2[&quot;name: qwen-14b&lt;br&gt;provider: SiliconFlow&quot;]
        M3[&quot;name: gemini-pro&lt;br&gt;provider: Google Gemini&quot;]
        M4[&quot;name: llama3-local&lt;br&gt;provider: Local Ollama&quot;]
    end

    subgraph 应用层 [Model Tasks]
        T1[&quot;task: replyer_1&lt;br&gt;model_list: [deepseek-v3.1, gemini-pro]&quot;]
        T2[&quot;task: planner&lt;br&gt;model_list: [qwen-14b]&quot;]
        T3[&quot;task: utils_small&lt;br&gt;model_list: [llama3-local]&quot;]
    end

    P1 --&gt; M1
    P1 --&gt; M2
    P2 --&gt; M3
    P3 --&gt; M4

    M1 --&gt; T1
    M3 --&gt; T1
    M2 --&gt; T2
    M4 --&gt; T3</pre><ul><li><strong>解读</strong>：<code>replyer_1</code> 任务由 <code>deepseek-v3.1</code> 和 <code>gemini-pro</code> 两个引擎共同负责，它们分别来自 <code>SiliconFlow</code> 和 <code>Google Gemini</code> 两个不同的资源提供商。这种多模型、多供应商的配置，赋予了系统更强的弹性和适应性。</li></ul><h2 id="第1章-资源层-api-providers" tabindex="-1">第1章：资源层 (API Providers) <a class="header-anchor" href="#第1章-资源层-api-providers" aria-label="Permalink to “第1章：资源层 (API Providers)”">​</a></h2><p>资源层是整个系统的基石。一个稳定、可靠、多元化的资源层,是 Neo-MoFox 能够持续提供高质量服务的前提。</p><h3 id="_1-1-多供应商策略" tabindex="-1">1.1 多供应商策略 <a class="header-anchor" href="#_1-1-多供应商策略" aria-label="Permalink to “1.1 多供应商策略”">​</a></h3><p>为什么要配置多个 Provider？</p><ul><li><strong>风险对冲</strong>：当某个服务商（如 DeepSeek）的 API 临时宕机或网络波动时，系统可以无缝切换到备用服务商（如 SiliconFlow），保证服务的连续性。</li><li><strong>成本优化</strong>：不同的服务商对同一款模型可能有不同的定价。你可以通过多供应商配置，灵活选择当前性价比最高的渠道。</li><li><strong>能力互补</strong>：某些特殊模型（如 Google 的 Gemini）只有特定的服务商提供。配置多个供应商可以让你博采众长。</li></ul><h3 id="_1-2-关键参数详解" tabindex="-1">1.2 关键参数详解 <a class="header-anchor" href="#_1-2-关键参数详解" aria-label="Permalink to “1.2 关键参数详解”">​</a></h3><p>让我们以一个推荐的 <strong>SiliconFlow</strong> 配置为例，深入了解每个参数的含义和作用。SiliconFlow 聚合了众多优秀模型，是新手和专家的理想选择。</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">api_providers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SiliconFlow&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # 提供商名称，在 Models 层使用</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">base_url = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.siliconflow.cn/v1&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # API 地址</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api_key = [                                </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># API 密钥，支持多 Key 轮询</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;sk-key_1_xxxxxxxxxxxx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;sk-key_2_xxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 推荐使用多Key轮询，提高稳定性</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client_type = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openai&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 客户端类型，通常使用 &quot;openai&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">max_retry = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                              # 最大重试次数</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">timeout = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">45</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                               # 超时时间（秒）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">retry_interval = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 重试间隔（秒）</span></span></code></pre></div><ul><li><strong><code>api_key</code></strong>: 支持字符串（单 Key）或列表（多 Key）。列表模式下会自动轮询，并具备故障转移功能。</li><li><strong><code>client_type</code></strong>: <ul><li><code>openai</code>: 适用于大多数兼容 OpenAI 接口的服务商（如 SiliconFlow, Ollama）。</li><li><code>gemini</code>: 仅用于 Google Gemini 原生 API。</li></ul></li><li><strong>重试配置</strong>: <code>max_retry</code>, <code>timeout</code>, <code>retry_interval</code> 提供了网络不稳时的自动重试机制。</li></ul><h2 id="第2章-能力层-models" tabindex="-1">第2章：能力层 (Models) <a class="header-anchor" href="#第2章-能力层-models" aria-label="Permalink to “第2章：能力层 (Models)”">​</a></h2><h3 id="_2-1-命名与标识" tabindex="-1">2.1 命名与标识 <a class="header-anchor" href="#_2-1-命名与标识" aria-label="Permalink to “2.1 命名与标识”">​</a></h3><ul><li><code>model_identifier</code>：这是模型在服务商的模型 ID”，必须严格按照服务商的文档填写，例如 <code>&quot;deepseek-ai/deepseek-v3.1&quot;</code>。</li><li><code>name</code>：这是你为这个模型取的“<strong>内部代号</strong>”，例如 <code>&quot;SiliconFlow-DeepSeek-v3.1-Actor&quot;</code>。这个代号必须是唯一的，并且将在应用层 (Model Tasks) 中被频繁调用。一个好的命名习惯（如 <code>供应商-模型名-用途</code>）能极大提升配置文件的可读性。</li></ul><h3 id="_2-2-成本控制单元-price-in-price-out" tabindex="-1">2.2 成本控制单元：<code>price_in</code> &amp; <code>price_out</code> <a class="header-anchor" href="#_2-2-成本控制单元-price-in-price-out" aria-label="Permalink to “2.2 成本控制单元：price_in &amp; price_out”">​</a></h3><p>这两个参数是实现精细化成本管理的关键。</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">models</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_identifier = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;deepseek-ai/deepseek-v3.1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SiliconFlow-DeepSeek-v3.1-Actor&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api_provider = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SiliconFlow&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">price_in = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 输入价格（元 / M token）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">price_out = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8.0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # 输出价格（元 / M token）</span></span></code></pre></div><ul><li>通过精确填写每个模型的调用成本,你可以利用 Neo-MoFox 内置的统计功能,为后续的成本优化提供数据支持。</li></ul><h3 id="_2-3-模型行为微调" tabindex="-1">2.3 模型行为微调 <a class="header-anchor" href="#_2-3-模型行为微调" aria-label="Permalink to “2.3 模型行为微调”">​</a></h3><h4 id="force-stream-mode-应对-急性子-模型" tabindex="-1"><code>force_stream_mode</code>：应对“急性子”模型 <a class="header-anchor" href="#force-stream-mode-应对-急性子-模型" aria-label="Permalink to “force_stream_mode：应对“急性子”模型”">​</a></h4><ul><li>某些模型或服务商默认或只支持流式输出（打字机效果）。当遇到非流式请求就报错时，开启 <code>force_stream_mode = true</code> 可以强制系统以流式方式与该模型通信，确保兼容性。</li></ul><h4 id="anti-truncation-保证信息的完整性" tabindex="-1"><code>anti_truncation</code>：保证信息的完整性 <a class="header-anchor" href="#anti-truncation-保证信息的完整性" aria-label="Permalink to “anti_truncation：保证信息的完整性”">​</a></h4><ul><li>在一些需要完整、结构化输出的场景（例如生成代码或长篇报告），模型的回答可能会因为达到最大长度限制而被“拦腰截断”。启用 <code>anti_truncation = true</code> 如果侦测到被截断的话就会自动重试</li></ul><h4 id="max-context-模型最大输入上下文-token-数" tabindex="-1"><code>max_context</code>: 模型最大输入上下文 token 数 <a class="header-anchor" href="#max-context-模型最大输入上下文-token-数" aria-label="Permalink to “max_context:  模型最大输入上下文 token 数”">​</a></h4><p>适当调整模型的上下文窗口大小，可以在保证回答质量的前提下，优化性能和成本。对于一些对上下文敏感的任务（如复杂对话或代码生成），可以适当增加 <code>max_context</code> 的值，以提供更多的历史信息给模型。</p><h4 id="tool-call-应对一些-老旧-的模型" tabindex="-1"><code>tool_call</code>：应对一些&quot;老旧&quot;的模型 <a class="header-anchor" href="#tool-call-应对一些-老旧-的模型" aria-label="Permalink to “tool_call：应对一些&quot;老旧&quot;的模型”">​</a></h4><ul><li>某些模型（尤其是一些老版本的模型）可能不支持 Neo-MoFox 的工具调用机制。当你遇到模型无法正确执行工具调用的情况时，开启 <code>tool_call = false</code> 可以让系统绕过工具调用的流程，直接将工具调用请求作为普通文本发送给模型，从而实现兼容性。</li></ul><h4 id="extra-params-释放模型的隐藏潜能" tabindex="-1"><code>extra_params</code>：释放模型的隐藏潜能 <a class="header-anchor" href="#extra-params-释放模型的隐藏潜能" aria-label="Permalink to “extra_params：释放模型的隐藏潜能”">​</a></h4><ul><li><p>这是一个高级定制功能，允许你向模型传递服务商 API 支持的、但 <code>model.toml</code> 中没有直接提供的额外参数。</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">models</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_identifier = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Qwen/Qwen3-8B&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;qwen3-8b-fast&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api_provider = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SiliconFlow&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">extra_params = { enable_thinking = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例：关闭qwen3模型的“思考”过程，以换取更快的响应速度</span></span></code></pre></div></li><li><p>要使用此功能，你必须仔细阅读并理解对应模型供应商的 API 文档，了解它们支持哪些独特的参数。</p></li></ul><h2 id="第3章-应用层配置-model-tasks" tabindex="-1">第3章：应用层配置 (Model Tasks) <a class="header-anchor" href="#第3章-应用层配置-model-tasks" aria-label="Permalink to “第3章：应用层配置 (Model Tasks)”">​</a></h2><h3 id="_3-1-任务角色分析" tabindex="-1">3.1 任务角色分析 <a class="header-anchor" href="#_3-1-任务角色分析" aria-label="Permalink to “3.1 任务角色分析”">​</a></h3><p>每个 <code>[model_task_config.*]</code> 都定义了一个独特的工作流。以下是几个核心任务的策略建议：</p><ul><li><p><strong><code>actor</code> (主要/次要回复)</strong>：作用：这是 Bot 的&quot;门面&quot;，负责主要的聊天回复和对话生成。直接影响聊天体验。建议为 <code>actor</code> 配置你最强大、最昂贵的模型（如 DeepSeek V3.1, Kimi K2），以保证核心聊天体验。</p></li><li><p><strong><code>sub_actor</code> (决策模型)</strong>：这是 Bot 的“大脑”。它负责智能判断 Bot 是否需要对新消息进行响应,此任务对模型的逻辑推理和指令遵循能力要求极高。推荐使用逻辑性强的模型，即使它不是最“能聊”的。</p></li><li><p><strong><code>utils_small</code> (高频工具)</strong>：用于处理一些内部的、高频次的简单文本处理任务。<strong>强烈建议</strong>为此任务配置一个速度快、成本极低的小模型（甚至是本地模型）如（Qwen3-8B），能显著降低整体运营成本。</p></li><li><p><strong><code>utils</code> (工具模型)</strong>：Neo-MoFox 系统中各种功能组件使用的通用模型，要求兼顾性能和成本。建议选择一个性价比高的模型，既能保证准确性，又不会过度消耗资源。</p></li><li><p><strong><code>vlm</code> / <code>voice</code> / <code>embedding</code> (多模态与嵌入)</strong>：这些是功能性任务，必须配置支持相应能力的专用模型。例如，<code>vlm</code> 任务需要配置像 <code>qwen-vl</code> 这样的视觉语言模型。</p></li></ul><h3 id="_3-2-任务配置参数分析" tabindex="-1">3.2 任务配置参数分析 <a class="header-anchor" href="#_3-2-任务配置参数分析" aria-label="Permalink to “3.2 任务配置参数分析”">​</a></h3><ul><li><strong><code>concurrency_count</code></strong>：针对高频任务（如 <code>vlm</code> 图像识别），可设置 <code>concurrency_count</code> 以支持并行请求，提升响应速度,也提高一点稳定性。</li><li><strong><code>embedding_dimension</code></strong>：对于 <code>embedding</code> 任务，必须指定 <code>embedding_dimension</code>（如 1024、2048，具体参数请参考你的模型供应商文档），以确保向量化输出的正确性。</li></ul><h2 id="_4-负载均衡-load-balancing" tabindex="-1">4. 负载均衡 (Load Balancing) <a class="header-anchor" href="#_4-负载均衡-load-balancing" aria-label="Permalink to “4. 负载均衡 (Load Balancing)”">​</a></h2><p>Neo-MoFox 支持在 <code>model_list</code> 中配置多个模型，通过策略实现负载均衡。</p><h3 id="_4-1-策略类型" tabindex="-1">4.1 策略类型 <a class="header-anchor" href="#_4-1-策略类型" aria-label="Permalink to “4.1 策略类型”">​</a></h3><ul><li><strong><code>RoundRobinPolicy</code></strong>: 简单轮询，依次使用列表中的模型。</li><li><strong><code>LoadBalancedPolicy</code></strong> (默认): 动态负载均衡，根据模型评分选择最优模型。</li></ul><h3 id="_4-2-loadbalancedpolicy-机制" tabindex="-1">4.2 LoadBalancedPolicy 机制 <a class="header-anchor" href="#_4-2-loadbalancedpolicy-机制" aria-label="Permalink to “4.2 LoadBalancedPolicy 机制”">​</a></h3><p>启用该策略后，系统根据以下维度动态评分，选择分值最低（即最优）的模型：</p><ol><li><strong>长期成本 (<code>total_tokens</code>)</strong>: 倾向于使用积累消耗较少的模型。</li><li><strong>短期轮询 (<code>usage_penalty</code>)</strong>: 临时增加刚使用的模型分值，确保均匀分布。</li><li><strong>故障规避 (<code>penalty</code>)</strong>: 失败的模型会被大幅惩罚，实现自动故障转移。</li><li><strong>低延迟优先 (<code>avg_latency</code>)</strong>: 优先选择响应更快的模型。</li></ol><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">model_task_config</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">actor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model_list = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SiliconFlow-DeepSeek-v3.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Backup-Model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 系统将根据评分在列表中动态选择</span></span></code></pre></div><h2 id="_5-故障排查-troubleshooting" tabindex="-1">5 故障排查 (Troubleshooting) <a class="header-anchor" href="#_5-故障排查-troubleshooting" aria-label="Permalink to “5 故障排查 (Troubleshooting)”">​</a></h2><p>配置一个复杂的系统，难免会遇到问题。学会诊断问题是成为指挥官的必修课。</p><ul><li><strong>API Key 失效 / <code>401 Unauthorized</code></strong>：这是最常见的问题。请检查 <code>api_key</code> 是否填写正确、是否已过期、账户是否欠费。</li><li><strong>连接超时</strong>：如果日志中频繁出现 <code>Timeout</code> 错误，请适当增加对应 <code>api_provider</code> 的 <code>timeout</code> 值。</li><li><strong>配置不生效</strong>:修改 <code>model.toml</code> 后,需要<strong>重启 Neo-MoFox</strong> 才能让新的配置生效。</li></ul>`,52)),a("blockquote",null,[i[1]||(i[1]=a("p",null,[a("strong",null,"需要更详细的帮助？"),l(" 我们为您整理了一份详尽的常见问题列表。当您遇到棘手的错误时，请首先查阅：")],-1)),a("ul",null,[a("li",null,[a("strong",null,[s(o,{href:"./model_config_faq.html"},{default:c(()=>[...i[0]||(i[0]=[l("模型配置常见问题解答 (FAQ)",-1)])]),_:1})])])])]),s(n),s(t)])}const x=r(k,[["render",g]]);export{F as __pageData,x as default};
